    // Delayed shipment: no deliveredDate, past slaDate
    if (
      a.shipments?.some(
        (s) => !s.deliveredDate && new Date(s.slaDate) < nowDate
      )
    ) {
      signals.push("Delayed shipment");
    }

    // Escalated support: open case with high or critical severity
    if (
      a.supportCases?.some(
        (c) => c.status === "open" && ["high", "critical"].includes(c.severity)
      )
    ) {
      signals.push("Escalated support");
    }

    // Usage decline: current <= prior * 0.7
    if (
      a.usage &&
      a.usage.currentPeriodUnits <= a.usage.priorPeriodUnits * 0.7
    ) {
      signals.push("Usage decline");
    }

