        body:
          `Dear ${a.name} team, we have identified elevated risk signals on your account and have activated our ` +
          `executive recovery process. Our teams are actively reviewing your account to ensure continuity of service. ` +
          `A dedicated representative will be in touch shortly to address any concerns.`,
        created_at: nowDate,
      });

      await db.collection("audit_events").insertOne({
        event: "escalation_activated",
        description: `Escalation workflow activated for ${a.name}. ${riskSummary}.`,
        customer_visible: true,
        created_at: nowDate,
      });
    }
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}
